arguments.command:
cd /app && python3 -c "
import json,subprocess
d=json.load(open('/tmp/seqs.json')); inp=d['inp']
comp={'A':'T','T':'A','G':'C','C':'G'}
def rc(s): return ''.join(comp[c] for c in reversed(s))
def tm(s):
    r=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',s],capture_output=True,text=True)
    return float(r.stdout.strip())
# forward annealing: downstream top strand starting inp[216]
print('FORWARD (downstream) annealing candidates:')
for L in range(15,31):
    s=inp[216:216+L]
    print(L, round(tm(s),2), s)
print()
print('REVERSE (upstream revcomp) annealing candidates:')
for L in range(15,31):
    s=rc(inp[215-L:215])
    print(L, round(tm(s),2), s)
"

